SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Number of arms", "Control arm", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Colorectal' AND "Number of arms" >= 4 AND "Control arm" = 'Chemo/Anti-EGFR+Radiotherapy';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Monotherapy/combination", "Cancer type", "Type of combination", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Renal cell' AND "Name of ICI" = 'Tremelimumab' AND "Monotherapy/combination" = 'Combination';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Bladder' AND "Class of ICI" = 'CTLA-4' AND "Year" >= 2018;

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Atezolizumab+Trastuzumab emtansine+Placebo' AND "Cancer type" = 'Small Cell Lung' AND "Trial phase" = 'Phase 3';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Nivolumab, Ipilimumab' AND "Cancer type" = 'Gastric/GEJ' AND "Trial phase" = 'Phase 3';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Type of combination", "Cancer type", "Treatment regimen", "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Type of combination" = 'ICI+Vaccine';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Type of combination", "Cancer type", "Treatment regimen", "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Esophageal/GEJ' AND "Type of combination" = 'ICI+Chemo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Tremelimumab' AND "Cancer type" = 'Prostate' AND "Trial phase" = 'Phase 3';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Control arm", "Cancer type", "Trial name", "Treatment regimen"
