SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Control arm", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Durvalumab, Tremelimumab' AND "Cancer type" = 'Mesothelioma' AND "Control arm" = 'Radiation';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Number of arms", "Control arm", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Number of arms" >= 4 AND "Control arm" = 'Anti-VEGF';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Avelumab' AND "Cancer type" = 'Colorectal' AND "Trial phase" = 'Phase 2';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Control arm", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Tremelimumab' AND "Cancer type" = 'Hepatocellular' AND "Control arm" = 'Chemo/Anti-EGFR+Radiotherapy';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial phase", "Control arm", "Cancer type", "Name of ICI", "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Urothelial' AND "Trial phase" = 'Phase 3' AND "Control arm" = 'TKI';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Control arm", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Ipilimumab' AND "Cancer type" = 'Bladder' AND "Control arm" = 'Chemoradio';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Control arm", "Cancer type", "Control regimen", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Esophageal/GEJ' AND "Control arm" = 'Placebo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial phase", "Control arm", "Cancer type", "Name of ICI", "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Pancreatic' AND "Trial phase" = 'Phase 3' AND "Control arm" = 'Antibody-drug conjugate';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Durvalumab' AND "Cancer type" = 'Small Cell Lung' AND "Trial phase" = 'Phase 2';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Is PD-L1 positivity inclusion criteria", "Class of ICI", "Cancer type", "Name of ICI", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'NSCLC' AND "Class of ICI" = 'PD-L1' AND "Is PD-L1 positivity inclusion criteria" = 'Yes';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Control arm", "Cancer type", "Control regimen", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Colorectal' AND "Control arm" = 'Radiation';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type"
FROM clinical_trials
WHERE "Name of ICI" = 'Brentuximab-vedotin' AND "Cancer type" = 'Small Cell Lung' AND "Trial phase" = 'Phase 3' AND "Originial publication or Follow-up" = 'Original publication';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Monotherapy/combination", "Cancer type", "Total sample size", "Trial phase"
FROM clinical_trials
WHERE "Name of ICI" = 'Nivolumab, Ipilimumab' AND "Cancer type" = 'Mesothelioma' AND "Monotherapy/combination" = 'Monotherapy';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Included in MA", "Class of ICI", "Cancer type", "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Prostate' AND "Class of ICI" = 'PD1, CTLA-4' AND "Included in MA" = 'Yes';
